import './TimePickerRangeSplit.scss';

import React, { forwardRef, useEffect, useImperativeHandle, useRef, useState } from 'react';

import { classNames } from '../../../helpers/classnames';
import { TimePicker } from '../TimePicker';
import type { SingleTimeValue } from '../TimePicker.types';
import type { TimePickerRangeSplitProps } from './TimePickerRangeSplit.types';

export const TimePickerRangeSplit = forwardRef<TimePickerRangeSplitProps, TimePickerRangeSplitProps>(
	(
		{
			className,
			disableStartTime = false,
			disableEndTime = false,
			errorEnd = false,
			errorStart = false,
			defaultValueStart = '',
			defaultValueEnd = '',
			step = '60',
			onChange,
			size = 'small',
			fullWidth = false,

			...restProps
		},
		forwardedRef,
	) => {
		const [inputStartValue, setInputStartValue] = useState(defaultValueStart);
		const [inputEndValue, setInputEndValue] = useState(defaultValueEnd);
		const startRef = useRef(null);
		const endRef = useRef(null);
		const timeRangeRef = useRef({ start: startRef, end: endRef });

		useImperativeHandle<
			TimePickerRangeSplitProps,
			TimePickerRangeSplitProps & {
				startRef: HTMLInputElement;
				endRef: HTMLInputElement;
			}
		>(
			forwardedRef,
			() => ({
				startRef: timeRangeRef.current.start.current,
				endRef: timeRangeRef.current.end.current,
			}),
			[timeRangeRef],
		);

		const handleInputStartChange = (value: SingleTimeValue): void => {
			setInputStartValue(value);
		};

		const handleInputEndChange = (value: SingleTimeValue): void => {
			setInputEndValue(value);
		};

		useEffect(() => {
			onChange?.({ startTime: inputStartValue, endTime: inputEndValue });
		}, [inputStartValue, inputEndValue, onChange]);

		return (
			<div
				data-testid="TimePickerRangeSplit"
				className={classNames('dsb_timepicker-range-split', fullWidth && 'dsb_timepicker__full-width', className)}
			>
				<TimePicker
					name="start"
					ref={startRef}
					step={step}
					size={size}
					fullWidth={fullWidth}
					disabled={disableStartTime}
					onChange={handleInputStartChange}
					error={errorStart}
					defaultValue={defaultValueStart}
					{...restProps}
				/>
				<span className="separator">&#8211;</span>
				<TimePicker
					name="end"
					ref={endRef}
					step={step}
					size={size}
					showIcon={false}
					fullWidth={fullWidth}
					disabled={disableEndTime}
					onChange={handleInputEndChange}
					error={errorEnd}
					defaultValue={defaultValueEnd}
					{...restProps}
				/>
			</div>
		);
	},
);

TimePickerRangeSplit.displayName = 'TimePickerRangeSplit';
